import boto3
import sys
from urllib.parse import urlparse
from botocore.exceptions import ClientError

def create_sns_subscription(topic_arn, endpoint):
    try:
        sns = boto3.client('sns')
        response = sns.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=endpoint
        )
        return response
    except ClientError as e:
        print(f"Error creating subscription: {e}")
        return None

def validate_url(endpoint):
    try:
        result = urlparse(endpoint)
        return all([result.scheme, result.netloc]) and result.scheme in ['http', 'https']
    except Exception:
        return False

def main():
    if len(sys.argv) != 2:
        print("Usage: python sns_subscriber.py <topic_arn>")
        sys.exit(1)
    
    topic_arn = sys.argv[1]
    
    print("Enter subscription endpoints (press Enter twice to finish):")
    endpoints = []
    
    while True:
        endpoint = input("Endpoint: ").strip()
        if not endpoint:
            break
        if validate_url(endpoint):
            endpoints.append(endpoint)
        else:
            print("Invalid URL, skipping...")
    
    if not endpoints:
        print("No valid endpoints provided.")
        sys.exit(1)
    
    for endpoint in endpoints:
        print(f"Creating subscription for {endpoint}")
        response = create_sns_subscription(topic_arn, endpoint)
        if response:
            print(f"Subscription created: {response['SubscriptionArn']}")
        else:
            print(f"Failed to create subscription for {endpoint}")

if __name__ == "__main__":
    main()